import json
import pandas as pd
import os

# Get children's books data (direct list)
children_books = vars().get('var_functions.query_db:12', [])

# Get the review data file path and load it
reviews_file_path = vars().get('var_functions.query_db:10', '')
reviews_2020 = []

if reviews_file_path and isinstance(reviews_file_path, str) and os.path.exists(reviews_file_path):
    try:
        with open(reviews_file_path, 'r') as f:
            reviews_2020 = json.load(f)
    except:
        # If direct load fails, try to read as text and parse
        try:
            with open(reviews_file_path, 'r') as f:
                content = f.read()
                if content.strip():
                    reviews_2020 = json.loads(content)
        except:
            reviews_2020 = []

# If reviews_2020 is still empty, try alternative approaches
if not reviews_2020:
    # Maybe the data is stored differently
    for key, value in vars().items():
        if 'query_db:10' in key and isinstance(value, list):
            reviews_2020 = value
            break

# Ensure we have lists
if not isinstance(children_books, list):
    children_books = []
if not isinstance(reviews_2020, list):
    reviews_2020 = []

# Convert to DataFrames
df_books = pd.DataFrame(children_books) if children_books else pd.DataFrame()
df_reviews = pd.DataFrame(reviews_2020) if reviews_2020 else pd.DataFrame()

if df_books.empty or df_reviews.empty:
    result = json.dumps([])
else:
    # Clean and convert data types
    df_reviews['rating'] = pd.to_numeric(df_reviews['rating'], errors='coerce')
    df_reviews['book_id'] = df_reviews['purchase_id']

    # Merge books and reviews on book_id/purchase_id
    merged_df = df_books.merge(df_reviews[['book_id', 'rating']], on='book_id', how='inner')

    if merged_df.empty:
        result = json.dumps([])
    else:
        # Calculate average rating per book
        book_ratings = merged_df.groupby(['book_id', 'title']).agg({
            'rating': ['count', 'mean']
        }).reset_index()

        # Flatten column names
        book_ratings.columns = ['book_id', 'title', 'review_count', 'avg_rating']

        # Filter books with average rating >= 4.5 and at least 1 review
        high_rated_books = book_ratings[(book_ratings['avg_rating'] >= 4.5) & (book_ratings['review_count'] >= 1)]

        # Sort by average rating descending
        if not high_rated_books.empty:
            high_rated_books = high_rated_books.sort_values('avg_rating', ascending=False)
            result = high_rated_books.to_json(orient='records')
        else:
            result = json.dumps([])

print('__RESULT__:')
print(result)

